                     const std::vector<T>& records) {
  sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::write(records))
      .value();
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                               const T& record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Map table names to their primary key column names
  std::map<std::string, std::string> pk_map = {
      {"Student", "SNo"},
      {"Course", "CID"},
      {"Score", "ScID"},
      {"Major", "MID"}
  };

  std::string pk_col = pk_map[table_name];

  // Construct UPDATE SQL statement
  std::string sql = "UPDATE " + table_name + " SET " + col_name + " = ";

  // Handle different value types (try numeric first, otherwise treat as string)
  try {
    std::stod(new_value);  // Test if it's numeric
    sql += new_value;
  } catch (...) {
    sql += "'" + new_value + "'";
  }

  sql += " WHERE " + pk_col + " = ";

  // Handle different ID types
  if (table_name == "Student") {
    sql += "'" + std::to_string(record_id) + "'";
  } else {
    sql += std::to_string(record_id);
  }

  sqlgen::exec(conn, sql).value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Map table names to their primary key column names
  std::map<std::string, std::string> pk_map = {
      {"Student", "SNo"},
      {"Course", "CID"},
      {"Score", "ScID"},
      {"Major", "MID"}
  };

  std::string pk_col = pk_map[table_name];

  // Construct DELETE SQL statement
  std::string sql = "DELETE FROM " + table_name + " WHERE " + pk_col + " = ";

  // Student table uses string primary key, others use integer
  if (table_name == "Student") {
    sql += "'" + record_id + "'";
  } else {
    sql += record_id;
  }

  sqlgen::exec(conn, sql).value();
}
