      return conn
        .and_then(
          from<Course>
          | left_join<Enrollment>("course_id"_c)
          | group_by("course_id"_c, "title"_c)
          | select(
              "title"_c,
              count("enrollment_id"_c).as("student_count"),
              avg("grade"_c).as("avg_grade")
            )
          | read<std::vector<CourseStats>>
        );
    });

  if (result) {
    return *result;
  }

  return std::vector<CourseStats>{};
