 * - Call manage_indexes
 * - Verify indexes exist
 * - Verify uniqueness constraint on SKU
 */
TEST(sqlite, manage_indexes) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Cleanup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Product>(conn);

  // 1. Call manage_indexes (will create table and indexes)
  bool success = manage_indexes();
  EXPECT_TRUE(success);

  // 2. Verify indexes exist
  auto check_idx = exec(conn, "PRAGMA index_list('Product');");
  EXPECT_TRUE(check_idx.has_value());
  // We could parse the output to be stricter, but execution success implies indexes were created or existed

  // 3. Verify uniqueness constraint on SKU
  Product p1{.product_id = 1, .sku = "SKU001", .name = "Product 1", .category = "Cat A", .price = 10.0};
  insert(conn, std::vector{p1});

  Product p2{.product_id = 2, .sku = "SKU001", .name = "Product 2", .category = "Cat B", .price = 20.0};
  auto insert_dup = insert(conn, std::vector{p2});

  EXPECT_FALSE(insert_dup.has_value()); // Should fail due to unique index on sku
}

