```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    if (ids.empty()) {
        return true;
    }

    using namespace sqlgen;

    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn.has_value()) {
        return false;
    }

    // Build IN clause for batch update
    std::string placeholders;
    for (size_t i = 0; i < ids.size(); ++i) {
        if (i > 0) placeholders += ", ";
        placeholders += std::to_string(ids[i]);
    }

    // Execute the UPDATE statement with IN clause
    std::string sql = "UPDATE Document SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP WHERE doc_id IN (" + placeholders + ")";

    conn = conn.and_then([&sql](auto connection) {
        connection.execute(sql);
        return connection;
    });

    return conn.has_value();
}

}  // namespace soft_delete_records
```

This implementation:

1. **Validates input**: Returns `true` early if the IDs list is empty (no-op success)
2. **Connects to database**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to open the specified database
3. **Builds batch UPDATE**: Creates an IN clause with all document IDs to update in a single SQL statement
4. **Soft deletes records**: Executes `UPDATE Document SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP WHERE doc_id IN (...)` 
5. **Uses monadic pattern**: Chains operations using `.and_then()` following sqlgen's functional programming style
6. **Returns status**: Returns `true` if the operation succeeded, `false` otherwise

The approach uses a single UPDATE statement with an IN clause for better performance compared to individual updates per ID.

