bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;

  try {
    // Connect to the SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite").value();

    // Begin transaction
    db.execute("BEGIN TRANSACTION");

    // Update sender account - deduct amount only if sufficient balance exists
    auto sender_update = db.execute(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    // Check if the update affected any rows (means sufficient funds existed)
    if (sender_update.rows_affected() == 0) {
      // Insufficient funds or account doesn't exist - rollback
      db.execute("ROLLBACK");
      return false;
    }

    // Update receiver account - add amount
    auto receiver_update = db.execute(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    // Check if receiver update was successful
    if (receiver_update.rows_affected() == 0) {
      // Receiver account doesn't exist - rollback
      db.execute("ROLLBACK");
      return false;
    }

    // Commit transaction
    db.execute("COMMIT");

    return true;
  } catch (...) {
