// update_eas_table.hpp
#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  design_eas_database_with_major();

  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new column Grade to Score table
        return sqlgen::exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'F';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify the column type of Age in Student table
        // Note: SQLite has limited ALTER TABLE support
        // To modify a column type, we need to recreate the table
        return sqlgen::exec(conn, "PRAGMA foreign_keys = OFF;");
      })
      .and_then([](auto&& conn) {
        return sqlgen::exec(conn, "BEGIN TRANSACTION;");
      })
      .and_then([](auto&& conn) {
        // Create new table with Age as INT NULL
        return sqlgen::exec(conn,
            "CREATE TABLE Student_new ("
            "SNo VARCHAR(10) PRIMARY KEY, "
            "SName VARCHAR(30) NOT NULL, "
            "Sex INTEGER NOT NULL DEFAULT 1, "
            "Birthday DATETIME, "
            "Major INTEGER, "
            "Scorses REAL, "
            "Remark TEXT, "
            "Age INTEGER"
            ");");
      })
      .and_then([](auto&& conn) {
        // Copy existing data
        return sqlgen::exec(conn,
            "INSERT INTO Student_new (SNo, SName, Sex, Birthday, Major, Scorses, Remark) "
            "SELECT SNo, SName, Sex, Birthday, Major, Scorses, Remark FROM Student;");
      })
      .and_then([](auto&& conn) {
        return sqlgen::exec(conn, "DROP TABLE Student;");
      })
      .and_then([](auto&& conn) {
        return sqlgen::exec(conn, "ALTER TABLE Student_new RENAME TO Student;");
      })
      .and_then([](auto&& conn) {
        return sqlgen::exec(conn, "COMMIT;");
      })
      .and_then([](auto&& conn) {
        return sqlgen::exec(conn, "PRAGMA foreign_keys = ON;");
      })
      .and_then([](auto&& conn) {
        // 3. Drop the Major table
        return sqlgen::exec(conn, "DROP TABLE Major;");
      })
      .value();
}

} // namespace update_eas_table

