```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to the SQLite database
  // Note: SQLite doesn't support RIGHT JOIN directly, so we use LEFT JOIN with tables swapped
  // This effectively gives us all projects, with department info where available
  auto result = sqlite::connect("test_db.sqlite")
    .and_then([](auto conn) {
      // Since sqlgen may not have native RIGHT JOIN support for SQLite,
      // we emulate it using LEFT JOIN: Project LEFT JOIN Department
      // This includes all projects (even those without departments)
      return conn.template execute<std::vector<DepProj>>(
        R"(SELECT d.name as department_name, p.name as project_name 
           FROM Project p 
           LEFT JOIN Department d ON p.department_id = d.department_id)"
      );
    });

  // Return the result or an empty vector if the operation failed
  return result.value_or(std::vector<DepProj>{});
}

}  // namespace right_join_departments_projects
```

**Note:** This implementation takes into account that:
1. SQLite doesn't natively support RIGHT JOIN (it was added in SQLite 3.39.0), so we use `LEFT JOIN` with tables swapped to achieve the same effect
2. The `DepProj` struct indicates that `project_name` is required and `department_name` is optional, suggesting we're including all projects (even those without department associations)
3. The implementation uses the sqlgen library's `connect()` and `execute()` methods following the patterns shown in the provided code examples
4. Error handling returns an empty vector if the database operation fails

If you actually need all departments (with optional projects), you would swap the join to: `FROM Department d LEFT JOIN Project p ON d.department_id = p.department_id`, but this would require changing the struct to make `project_name` optional and `department_name` required.

