};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Construct a query with where, order_by, and limit clauses
  // Filtering for records where score > 10
  const auto query = sqlgen::read<std::vector<B>> |
                     where("score"_c > 10.0 && "a_id"_c > 0) |
                     order_by("score"_c) |
                     limit(10);

  // Generate SQL string for SQLite without execution (dry run)
  // This is useful for debugging and verifying the generated SQL
  std::string sql = sqlgen::sqlite::to_sql(query);

  return sql;
}

}  // namespace generate_sql_dry_run
