```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // Create the Event table if it doesn't exist
  db.execute(sqlgen::CreateTable<Event>{});

  // Insert events into the table
  if (!events.empty()) {
    db.execute(sqlgen::Insert<Event>{events});
  }

  // Execute temporal analysis query using SQLite date/time functions
  const std::string query = R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      (julianday(end_time) - julianday(start_time)) as duration_days
    FROM Event
    WHERE end_time IS NOT NULL
  )";

  // Execute query and return results mapped to TemporalAnalysis
  return db.select<TemporalAnalysis>(query);
}

}  // namespace analyze_temporal_data
```

This implementation:

1. **Connects to SQLite database** `test_db.sqlite` using `sqlgen::sqlite::Database`

2. **Creates the Event table** using `sqlgen::CreateTable<Event>{}` to ensure the table structure exists

3. **Inserts the provided events** using `sqlgen::Insert<Event>{}` if the vector is not empty

4. **Executes temporal analysis query** using SQLite-specific date/time functions:
   - `strftime('%d', start_time)` - extracts day (01-31)
   - `strftime('%m', start_time)` - extracts month (01-12)
   - `strftime('%Y', start_time)` - extracts year
   - `strftime('%H', start_time)` - extracts hour (00-23)
   - `strftime('%M', start_time)` - extracts minute (00-59)
   - `strftime('%S', start_time)` - extracts second (00-59)
   - `strftime('%w', start_time)` - extracts weekday (0-6, Sunday is 0)
   - `strftime('%s', start_time)` - converts to Unix epoch timestamp
   - `julianday()` - calculates date differences in days

5. **Returns the results** as a `std::vector<TemporalAnalysis>` with all temporal components extracted and calculated for events that have non-null end times

