  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::Connection("test_db.sqlite");

  // Create tables
  conn.execute(CreateTable<User>{});
  conn.execute(CreateTable<Friendship>{});

  // Insert users
  for (const auto& user : users) {
    conn.execute(Insert{user});
  }

  // Insert friendships (bidirectional - add both directions for easier querying)
  for (const auto& friendship : friendships) {
    conn.execute(Insert{friendship});
    // Add reverse direction if not already present
    Friendship reverse{
      .user1_id = friendship.user2_id,
      .user2_id = friendship.user1_id,
      .created_at = friendship.created_at
    };
    conn.execute(Insert{reverse});
  }

  // Perform analysis queries:

  // 1. Find mutual friends using SELF-JOIN
  // Find pairs of users who are friends AND have common friends
  const std::string mutual_friends_query = R"(
    SELECT DISTINCT u1.username as user1_name, u2.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id
    INNER JOIN User u2 ON f2.user2_id = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u2.user_id
      )
    ORDER BY u1.username, u2.username
  )";

  // 2. Find users with above-average number of friends (nested query)
  const std::string popular_users_query = R"(
    SELECT u.username
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    HAVING COUNT(f.user2_id) > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user1_id)
    )
  )";

  // 3. Find friend-of-friend relationships (not direct friends)
  const std::string fof_query = R"(
    SELECT DISTINCT u1.username as user1_name, u3.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id
    INNER JOIN User u3 ON f2.user2_id = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u3.user_id
      )
  )";

  // 4. Count friends per user and identify most connected users
  const std::string friend_count_query = R"(
    SELECT u.username, COUNT(f.user2_id) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
  )";

  // Execute the mutual friends query and return results
  std::vector<FriendConnection> connections;

  auto result = conn.execute(Select<FriendConnection>().raw(mutual_friends_query));

  for (const auto& row : result) {
    connections.push_back(row);
  }

