```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a temporary SQLite table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite")
                  .and_then(create_table<Product> | if_not_exists)
                  .value();

  // Insert all products into the table
  for (const auto& product : products) {
    sqlgen::write(conn, product);
  }

  // Execute the mathematical operations query
  // The query computes various mathematical functions on the Product data
  const std::string query = R"(
    SELECT 
      product_id,
      name,
      ABS(price) as abs_price,
      CAST(CEIL(price) AS REAL) as ceil_price,
      CAST(FLOOR(price) AS REAL) as floor_price,
      ROUND(price, 2) as rounded_price,
      EXP(discount_rate/100.0) as exp_discount,
      LN(price) as ln_price,
      LOG2(quantity) as log2_quantity,
      SIN(discount_rate) as sin_discount,
      COS(discount_rate) as cos_discount,
      TAN(discount_rate) as tan_discount,
      SQRT(quantity) as sqrt_quantity
    FROM Product
  )";

  // Execute the query and map results to MathAnalysis struct
  auto results = sqlgen::read<std::vector<MathAnalysis>>(conn, query).value();

  return results;
}

}  // namespace mathematical_operations_analysis
