```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace inventory_bulk_write_and_read {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
  std::string location;
};

/**
 * description: inventory_bulk_write_and_read.
 * This function demonstrates how to perform bulk write and read operations on an inventory table.
 * It first drops and recreates the table, then writes the given items to the table.
 * Finally, it reads back the items with quantity > 50, orders them by quantity in descending order,
 * and returns true if at least one item is found.
 * Returns: bool.
 */
bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database, create table if needed, write items, then read with filters
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(create_table<Inventory> | if_not_exists)
    .and_then([&](auto&& conn) { return sqlgen::write(conn, items); })
    .and_then(read<std::vector<Inventory>> | 
              where("quantity"_c > 50) | 
              order_by(desc("quantity"_c)));

  // Return true if at least one item was found
  if (result) {
    return !result.value().empty();
  }
  return false;
}

}  // namespace inventory_bulk_write_and_read
```

This implementation:

1. **Connects to the SQLite database** `test_db.sqlite` using `sqlgen::sqlite::connect()`
2. **Creates the Inventory table** if it doesn't exist using `create_table<Inventory> | if_not_exists`
3. **Bulk writes** the inventory items using `sqlgen::write(conn, items)`
4. **Reads back filtered records** where `quantity > 50`, ordered by `quantity` in descending order using:
   - `where("quantity"_c > 50)` for filtering
   - `order_by(desc("quantity"_c))` for ordering
5. **Returns true** if at least one item is found in the filtered results, **false** otherwise

The function chains all operations using `.and_then()` which is the monadic pattern used by the sqlgen library, and uses the pipe operator `|` to compose operations and filters.

