```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database file
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Enable foreign key constraints (required for SQLite cascade delete)
  conn.execute("PRAGMA foreign_keys = ON;");

  // Drop tables if they exist (for clean demonstration)
  conn.execute("DROP TABLE IF EXISTS Child;");
  conn.execute("DROP TABLE IF EXISTS Parent;");

  // Create Parent and Child tables with cascade delete constraint
  conn.create_table<Parent>();
  conn.create_table<Child>();

  // Insert parent records
  Parent parent1{1, "Parent1"};
  Parent parent2{2, "Parent2"};
  conn.insert(parent1);
  conn.insert(parent2);

  // Insert child records - two children for parent_id=1, one for parent_id=2
  Child child1{1, 1, "Child of Parent1 - Record 1"};
  Child child2{2, 1, "Child of Parent1 - Record 2"};
  Child child3{3, 2, "Child of Parent2 - Record 1"};
  conn.insert(child1);
  conn.insert(child2);
  conn.insert(child3);

  // Delete parent with parent_id = 1
  // This should cascade delete child1 and child2
  conn.execute("DELETE FROM Parent WHERE parent_id = 1;");

  // Query remaining children to verify cascade deletion
  auto remaining_children = conn.select<Child>().execute();

  // Verify cascade delete worked correctly:
  // - Only 1 child should remain (child3 with parent_id = 2)
  // - Children with parent_id = 1 should be automatically deleted
  if (remaining_children.size() != 1) {
    return false;
  }

  // Verify the remaining child belongs to parent_id = 2
  return remaining_children[0].parent_id == 2;
}

}  // namespace cascade_delete_demo
