    Account{.account_id = 1, .balance = 1000.0, .status = "active"},
    Account{.account_id = 2, .balance = 2000.0, .status = "inactive"}
  };

  auto insert_result = create_result.and_then(write(initial_accounts));
  if (!insert_result) {
    return false;
  }

  // Update using set operations
  auto update_result = insert_result.and_then(
    update<Account> | 
    set("balance"_c = 1500.0, "status"_c = "updated") |
    where("account_id"_c == 1)
  );

  if (!update_result) {
    return false;
  }

  // Verify the update by reading back the data
  auto verify_result = update_result.and_then(
    read<Account> | where("account_id"_c == 1)
  );

  if (!verify_result) {
    return false;
  }

  // Check if the balance and status were updated correctly
  auto accounts = *verify_result;
  if (accounts.empty() || accounts[0].balance != 1500.0 || accounts[0].status != "updated") {
    return false;
  }

  return true;
}
