    Account{.account_id = 2, .balance = 2000.0, .status = "inactive"},
    Account{.account_id = 3, .balance = 1500.0, .status = "active"}
  };

  result = result.and_then(write(initial_accounts));
  if (!result) {
    return false;
  }

  // Step 3: Update balances and statuses using set(...)
  // Update account 1: change balance and status
  result = result.and_then(
