```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it
  // using UNION of LEFT JOIN and RIGHT JOIN (simulated)
  // However, given the SupProd structure (supplier_name is not optional),
  // we implement this as a LEFT JOIN from Supplier to Product,
  // which includes all suppliers and their associated products (if any)

  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Perform LEFT JOIN to get all suppliers with their products
  auto result = conn.and_then([](auto& db) {
    std::vector<SupProd> results;

    // Execute SQL query for LEFT JOIN
    auto stmt = db.prepare(
      "SELECT s.name as supplier_name, p.name as product_name "
      "FROM Supplier s "
      "LEFT JOIN Product p ON s.supplier_id = p.supplier_id"
    );

    if (stmt) {
