  using namespace sqlgen::literals;

  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it
  // using UNION of LEFT JOIN and RIGHT JOIN (simulated)
  // However, given the SupProd structure (supplier_name is not optional),
  // we implement this as a LEFT JOIN from Supplier to Product,
