```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace delete_with_complex_condition {

struct User {
  sqlgen::PrimaryKey<int> id;
  int age;
  std::string status;
};

/**
 * This function demonstrates deleting with complex conditions.
 * Returns: std::string.
 */
inline std::string delete_with_complex_condition() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct DELETE statement with complex OR condition:
    // age < 18 OR status = 'inactive'
    auto query = delete_from<User>() 
               | where(("age"_c < 18) || ("status"_c == "inactive"));

    // Convert the query to SQL string
    return to_sql(query);
}

}  // namespace delete_with_complex_condition
```

## Explanation:

1. **Using directives**: Include `sqlgen` and `sqlgen::literals` namespaces for cleaner syntax
2. **DELETE statement**: `delete_from<User>()` constructs a DELETE statement for the User table
3. **Complex condition**: 
   - Use `"age"_c` and `"status"_c` (column literals) to reference table columns
   - Combine conditions with `||` (logical OR operator)
   - `"age"_c < 18` checks if age is less than 18
   - `"status"_c == "inactive"` checks if status equals 'inactive'
4. **Chaining**: Use the `|` operator to chain the `where` clause to the DELETE statement
5. **SQL generation**: `to_sql()` converts the query object to its SQL string representation

The generated SQL should be equivalent to:
```sql
DELETE FROM User WHERE age < 18 OR status = 'inactive'
```

