Here's the complete file:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_index_basic {

struct Book {
  sqlgen::PrimaryKey<int> id;
  std::string title;
};

/**
 * This function demonstrates creating an index.
 */
inline auto create_index_basic() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    return create_index<"idx_book_title", Book>("title"_c);
}

}  // namespace create_index_basic
```

**Explanation:**
1. The `Book` struct is already defined with an `id` primary key and a `title` field.
2. The function uses `create_index<"idx_book_title", Book>("title"_c)` to construct a CREATE INDEX statement:
   - `"idx_book_title"` is the name of the index as a template parameter
   - `Book` is the struct/table type
   - `"title"_c` specifies the column to index (the `_c` suffix is a user-defined literal from `sqlgen::literals`)
3. The function returns the query object which can be chained with other operations (like `and_then` with a database connection).

