  insert(conn, std::vector<Product>{{1, "A", "C1", 10.0}, {2, "B", "C2", 20.0}, {3, "C", "C1", 5.0}});
  insert(conn, std::vector<Sales>{{1, 1, 2, sqlgen::Date{"2024-01-01"}},
