namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Connect to SQLite database
  auto conn = sqlite::connect("test_db.sqlite");

  // Execute SQL query to analyze sales by weekday
  // strftime('%w', sale_time) extracts weekday from timestamp (0=Sunday, 6=Saturday)
  const auto query = R"(
    SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday, 
           SUM(quantity) as total_quantity
    FROM Sales
    GROUP BY strftime('%w', sale_time)
    ORDER BY weekday
  )";

  // Execute query and map results to WeekdayStats
  auto results = conn.execute_query<WeekdayStats>(query);

  return results;
}

}  // namespace weekday_sales_analysis
```

