#include <gtest/gtest.h>
#include "create_table_as_select.hpp"

TEST(create_table_as_select, test_query_generation) {
    auto query = create_table_as_select::create_table_as_select();
    std::string sql = sqlgen::sqlite::to_sql(query);

    EXPECT_TRUE(sql.find("CREATE TABLE") != std::string::npos);
    EXPECT_TRUE(sql.find("Target") != std::string::npos);
    EXPECT_TRUE(sql.find("AS SELECT") != std::string::npos || sql.find("AS") != std::string::npos);
    EXPECT_TRUE(sql.find("FROM") != std::string::npos);
    EXPECT_TRUE(sql.find("Source") != std::string::npos);
    EXPECT_TRUE(sql.find("WHERE") != std::string::npos);
    EXPECT_TRUE(sql.find("value") != std::string::npos);
    EXPECT_TRUE(sql.find("100") != std::string::npos);
}

related functions.definition:
template <rfl::internal::StringLiteral _alias, class QueryType,
          class... FieldTypes>
inline auto select_from(const QueryType& _query, const FieldTypes&... _fields) {
  using FieldsType =
      rfl::Tuple<typename internal::GetColType<FieldTypes>::Type...>;
  return SelectFrom<QueryType, Literal<_alias>, FieldsType>{
      .fields_ =
          FieldsType(internal::GetColType<FieldTypes>::get_value(_fields)...),
      .from_ = _query};
}

